import{C as n,o as t,c as l,a5 as a,E as o}from"./chunks/framework.CW28V7p_.js";const k=JSON.parse('{"title":"5. Filesystem & permissions","description":"","frontmatter":{},"headers":[],"relativePath":"module-0/5-filesystem.md","filePath":"module-0/5-filesystem.md","lastUpdated":1780937944000}'),h={name:"module-0/5-filesystem.md"},c=Object.assign(h,{setup(r){const i={id:"m0-5-filesystem",title:"🧠 Mini-check: Filesystem & permissions",intro:"3 питання щоб закріпити permissions і symlinks.",questions:[{type:"diagnose",q:"Ти запускаєш /home/solana/ag/bin/solana slot як юзер devops_ssh БЕЗ sudo і отримуєш Permission denied. Файл solana має mode 755 (виконуваний для всіх). Чому помилка?",options:["Тому що папка /home/solana/ має mode 750 — devops_ssh не може traverse у неї без elevated permissions","Тому що binary потребує root capabilities","Тому що файл насправді не існує","Тому що SELinux блокує доступ"],correct:[0],explanation:"Це класичний footgun з §1 cheatsheet. /home/solana/ має mode 750 (rwxr-x---). Group execute (x) дозволяє traverse в папку для members групи solana. devops_ssh не в групі solana → не може traverse → не доходить до binary. Виконати solana --version через 750 директорію неможливо для не-member групи. Sudo обходить це бо root ignored всі permission checks."},{type:"command",q:"Як подивитись на що вказує symlink /home/solana/ag? Напиши команду.",accepts:["readlink /home/solana/ag","sudo readlink /home/solana/ag","ls -la /home/solana/ag","sudo ls -la /home/solana/ag","readlink -f /home/solana/ag"],ideal:"readlink /home/solana/ag",explanation:"readlink показує куди вказує symlink (raw target). readlink -f показує final resolved path (якщо це symlink на symlink — fully resolves). ls -la теж показує target через `->` нотацію. На сервері /home/solana/ має mode 750 тому додай sudo якщо ти devops_ssh."},{type:"scenario",q:"Тобі треба видалити всі файли у /home/solana/solana/ledger/ (повний wipe). Ти набираєш `sudo rm -rf /home/solana/solana/ledger/*` як devops_ssh — і нічого не видаляється. Чому і як виправити?",ideal:`Причина: shell expand* ПЕРЕД викликом sudo — а shell працює як devops_ssh. devops_ssh не може читати /home/solana/solana/ (mode 750), тому wildcard * не знаходить нічого для expand, лишається literal *. rm отримує литерал /home/solana/solana/ledger/* який нічого не матчить → silent no-op.

Fix варіант 1 (recommended): \`sudo bash -c "rm -rf /home/solana/solana/ledger/*"\` — bash тепер запускається ПІД root, ВІН expand * маючи доступ.

Fix варіант 2: \`sudo find /home/solana/solana/ledger -mindepth 1 -delete\` — find працює як root, traverses фолдер, видаляє content.

Це footgun який ти зловила під час cluster restart 2026-06-02.`,explanation:"Ключове розуміння: shell glob expansion timing. * розширюється ДО запуску sudo, у permissions shell-юзера. Якщо ти описала це + один з двох fixes — повна відповідь. Bonus якщо обидва варіанти."}]};return(d,s)=>{const e=n("Quiz");return t(),l("div",null,[s[0]||(s[0]=a("",78)),o(e,{data:i}),s[1]||(s[1]=a("",6))])}}});export{k as __pageData,c as default};
